import { FunctionComponent, VNode } from 'preact';
import { HTMLAttributes } from 'preact/compat';
import { classes, VComponent } from '@adobe-commerce/elsie/lib';
import '@/pdp/components/Header/Header.css';

export interface HeaderProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
  title: VNode;
  sku: VNode;
  hideSku?: boolean;
  /** When provided, displayed as variant name (e.g. when all options are selected on a configurable product) */
  variantName?: VNode;
  /** When provided, displayed as variant SKU (e.g. when all options are selected on a configurable product) */
  variantSku?: VNode;
}

export const Header: FunctionComponent<HeaderProps> = ({
  className,
  title,
  sku,
  hideSku = false,
  variantName,
  variantSku,
  children,
  ...props
}) => {
  return (
    <div {...props} className={classes(['pdp-header', className])}>
      <div className="pdp-header__title">
        <VComponent node={title} />
      </div>
      {!hideSku && (
        <div className="pdp-header__sku">
          <VComponent node={sku} />
        </div>
      )}
      {(variantName || variantSku) && (
        <div className="pdp-header__variant">
          {variantName && (
            <span className="pdp-header__variant-name">
              <VComponent node={variantName} />
            </span>
          )}
          {variantName && variantSku && (
            <span className="pdp-header__variant-separator"> – </span>
          )}
          {variantSku && (
            <span className="pdp-header__variant-sku">
              <VComponent node={variantSku} />
            </span>
          )}
        </div>
      )}
    </div>
  );
};
